class Solution:
    def solve(self, s: str) -> str:
        import re
        tags = re.findall(r'<[^>]*>', s)
        for tag in tags:
            tag = tag.strip('<>')
            if not tag[0].isalpha() or not all(c in 'abcdefghijklmnopqrstuvwxyz_/-' for c in tag):
                return 'Invalid tag: ' + tag
        return 'Valid HTML';
